/// <summary>
/// Business event class for ETG DMS Revere Integration.
/// Sends the event using the provided contract data.
/// </summary>
[BusinessEvents(classStr(ETGDMSRevereIntegrationContract),
"ETG DMS Revere Integration ",
    "This business event will trigger when a new record is created or updated.",
    ModuleAxapta::General)]
internal final class ETGDMSRevereIntegrationEventClass extends BusinessEventsBase
{
    private ETGDMSRevereIntegrationContract contract;


}

Method.Source:
public static ETGDMSRevereIntegrationEventClass newFromContract(ETGDMSRevereIntegrationContract _contract)
{
    ETGDMSRevereIntegrationEventClass event = new ETGDMSRevereIntegrationEventClass();
    event.parmDataContract(_contract);
    return event;
}

public ETGDMSRevereIntegrationContract parmDataContract(ETGDMSRevereIntegrationContract _contract = contract)
{
    contract = _contract;
    return contract;
}
